  /// Find stats by email
  static Map<String, dynamic>? findByEmail(String email) {
    try {
      return stats.firstWhere(
        (stat) => stat['Email'].toString().toLowerCase() == email.toLowerCase().trim(),
      );
    } catch (e) {
      return null;
    }
  }

  /// Find stats by ID (string)
  static Map<String, dynamic>? findById(String id) {
    try {
      return stats.firstWhere((stat) => stat['Id'] == id);
    } catch (e) {
      return null;
    }
  }

  /// Find stats by email or ID
  static Map<String, dynamic>? findByEmailOrId(String emailOrId) {
    // Try email first
    final byEmail = findByEmail(emailOrId);
    if (byEmail != null) return byEmail;
    
    // Try ID
    return findById(emailOrId);
  }
